                if (strpos($key, 'jit_debug') !== false || strpos($key, 'jit_bisect') !== false) return number_format($value);
                if (strpos($key, 'log_verbosity') !== false) return 'Level ' . $value;
                if (strpos($key, 'opt_debug') !== false) return 'Level ' . $value;
