                if (empty($value)) {
                    if (strpos($key, 'preload') !== false || strpos($key, 'blacklist') !== false || strpos($key, 'file_cache') !== false || strpos($key, 'mmap_base') !== false || strpos($key, 'error_log') !== false) return '(not set)';
